mapper.update:
UPDATE holdings
SET krw_cost_basis = krw_cost_basis * (quantity - #{qty}) / quantity,
    quantity       = quantity - #{qty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND quantity - held_quantity - #{qty} >= 0

UPDATE holdings
SET held_quantity = held_quantity + #{qty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND quantity - held_quantity - #{qty} >= 0

UPDATE holdings
SET held_quantity = held_quantity - #{qty}
WHERE account_id = #{accountId} AND stock_code = #{stockCode}
  AND held_quantity >= #{qty}
